import React from 'react';
import { useFormik } from 'formik';
import './App.css'; 
import Main from './main';
import { BrowserRouter, Route, Routes, useNavigate } from 'react-router-dom';
import { Formik, Form, Field } from 'formik';
import * as Yup from 'yup';

// Validation schema
const validationSchema = Yup.object().shape({
  Name: Yup.string().required('Full Name is required'),
  Address: Yup.string().required('Address is required'),
  mobile: Yup.string().required('Mobile Number is required'),
  city: Yup.string().required('City is required'),
  district: Yup.string().required('District is required'),
  census: Yup.string().required('Census Code is required'),
  feeder: Yup.string().required('Feeder Code is required'),
  subdivision: Yup.string().required('Subdivision Name is required'),
  routecode: Yup.string().required('Route Code is required'),
  billmonth: Yup.string().required('Bill Month is required'),
  billdate: Yup.string().required('Bill Date is required'),
  duedate: Yup.string().required('Due Date is required'),
  fromdate: Yup.string().required('From Date is required'),
  todate: Yup.string().required('To Date is required'),
  consumerno: Yup.string().required('Consumer No is required'),
  meterno: Yup.string().required('Meter No is required'),
  maxdemand: Yup.string().required('Max Demand is required'),
  feedercode: Yup.string().required('Feeder Code is required'),
  meterrentcode: Yup.string().required('Meter Rent Code is required'),
  unitcr: Yup.string().required('Unit (current reading) is required'),
  unitpr: Yup.string().required('Unit (past reading) is required'),
  unitc: Yup.string().required('Unit (consumption) is required'),
  reactiveunitcr: Yup.string().required('Reactive Unit(current reading) is required'),
  reactiveunitpr: Yup.string().required('Reactive Unit(past reading) is required'),
  reactiveunitc: Yup.string().required('Reactive Unit(consumption) is required'),
  importcr: Yup.string().required('Import(current reading) is required'),
  importpr: Yup.string().required('Import(past reading) is required'),
  importc: Yup.string().required('Import(consumption) is required'),
  exportcr: Yup.string().required('Export(current reading) is required'),
  exportpr: Yup.string().required('Export(past reading) is required'),
  exportc: Yup.string().required('Export(consumption) is required'),
  security: Yup.string().required('Security Deposit is required'),
  hpkw: Yup.string().required('HP/KW is required'),
  fixedcharge: Yup.string().required('Fixed Charge is required'),
  energycharge: Yup.string().required('Energy Charge is required'),
  mincharge: Yup.string().required('Minimum Charge is required'),
  reactivecharge: Yup.string().required('Reactive Charge is required'),
  toucharge: Yup.string().required('TOU Charge is required'),
  fuelcharge: Yup.string().required('Fuel Charge is required'),
  eleduty: Yup.string().required('Electricity Duty is required'),
  meterrent: Yup.string().required('Meter Rent is required'),
  fmc: Yup.string().required('Fuse misc. Charge is required'),
  dpc: Yup.string().required('DPC is required'),
  tamt: Yup.string().required('Total AMT is required'),
  pbill: Yup.string().required('Provisional Bill is required'),
  discreb: Yup.string().required('Discount/Rebate is required'),
  totalamt1: Yup.string().required('Total amount is required'),
  arrears: Yup.string().required('Arrears is required'),
  solarpr: Yup.string().required('Solar purchase rate is required'),
  solarbc: Yup.string().required('Solar banking charge is required'),
  totalamt2: Yup.string().required('Total amount is required'),
  govtrelief: Yup.string().required('Govt. Relief is required'),
  totalamt3: Yup.string().required('Total amount is required'),
  totalpayment: Yup.string().required('Total Payment is required'),
  adjustment: Yup.string().required('Adjustment is required'),
  fpppa: Yup.string().required('Tariff/fpppa Adjustment is required'),
  totalamt4: Yup.string().required('Total Bill Amt is required'),
  theft: Yup.string().required('Theft Arrears is required'),
  litigation: Yup.string().required('Litigation Arrears is required'),
  month1: Yup.string().required('Month 1 is required'),
  month2: Yup.string().required('Month 2 is required'),
  month3: Yup.string().required('Month 3 is required'),
  unitmonth1: Yup.string().required('Unit of Month 1 is required'),
  unitmonth2: Yup.string().required('Unit of Month 2 is required'),
  unitmonth3: Yup.string().required('Unit of Month 3 is required'),
  amountmonth1: Yup.string().required('Amount of Month 1 is required'),
  amountmonth2: Yup.string().required('Amount of Month 2 is required'),
  amountmonth3: Yup.string().required('Amount of Month 3 is required'),
});

const SignupForm = () => {
  const navigate = useNavigate();

  const formik = useFormik({
    initialValues: {
      Name: '',
      Address: '',
      mobile: '',
      city: '',
      district: '',
      census: '',
      feeder:  '',
      subdivision:  '',
      routecode:  '',
      billmonth:  '',
      billdate:  '',
      duedate:  '',
      fromdate:  '',
      todate:  '',
      consumerno:  '',
      meterno:  '',
      maxdemand:  '',
      feedercode:  '',
      meterrentcode:  '',
      unitcr:  '',
      unitpr:  '',
      unitc:  '',
      reactiveunitcr:  '',
      reactiveunitpr:  '',
      reactiveunitc:  '',
      importcr:  '',
      importpr:  '',
      importc:  '',
      exportcr:  '',
      exportpr:  '',
      exportc:  '',
      security:  '',
      hpkw:  '',
      fixedcharge:  '',
      energycharge:  '',
      mincharge:  '',
      reactivecharge:  '',
      toucharge:  '',
      fuelcharge:  '',
      eleduty:  '',
      meterrent:  '',
      fmc:  '',
      dpc:  '',
      tamt:  '',
      pbill:  '',
      discreb:  '',
      totalamt1:  '',
      arrears:  '',
      solarpr:  '',
      solarbc:  '',
      totalamt2:  '',
      govtrelief:  '',
      totalamt3:  '',
      totalpayment:  '',
      adjustment:  '',
      fpppa:  '',
      totalamt4:  '',
      theft:  '',
      litigation:  '',
      month1:  '',
      month2:  '',
      month3:  '',
      unitmonth1:  '',
      unitmonth2:  '',
      unitmonth3:  '',
      amountmonth1:  '',
      amountmonth2:  '',
      amountmonth3:  '',
    },
    validationSchema: validationSchema,
    onSubmit: (values) => {
      navigate('/main', { state: values });
    },
  });

  return (
    <div className="form-page">
      <h2>Enter Forms Details</h2>
    <form onSubmit={formik.handleSubmit} className='form-container'>

    <div className='input-main1'>
      <div className='b1-input'>
      <label htmlFor="Name">Full Name :</label><br />
      <input 
        name="Name" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.Name}
        className={formik.errors.Name && formik.touched.Name ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.Name && formik.touched.Name && <span className="error-message">{formik.errors.Name}</span>}
      <br />
      <label htmlFor="Address">Address :</label><br />
      <input 
        name="Address" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.Address}
        className={formik.errors.Address && formik.touched.Address ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.Address && formik.touched.Address && <span className="error-message">{formik.errors.Address}</span>}
      <br />
      <label htmlFor="mobile">Mobile Number :</label><br />
      <input 
        name="mobile" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.mobile}
        className={formik.errors.mobile && formik.touched.mobile ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.mobile && formik.touched.mobile && <span className="error-message">{formik.errors.mobile}</span>}
      <br />
      <label htmlFor="city">City :</label><br />
      <input 
        name="city" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.city}
        className={formik.errors.city && formik.touched.city ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.city && formik.touched.city && <span className="error-message">{formik.errors.city}</span>}
      <br />
      <label htmlFor="district">District :</label><br />
      <input 
        name="district" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.district}
        className={formik.errors.district && formik.touched.district ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.district && formik.touched.district && <span className="error-message">{formik.errors.district}</span>}
      <br />
      <label htmlFor="census">Census Code :</label><br />
      <input 
        name="census" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.census}
        className={formik.errors.census && formik.touched.census ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.census && formik.touched.census && <span className="error-message">{formik.errors.census}</span>}
      <br />
      <label htmlFor="feeder">Feeder Code :</label><br />
      <input 
        name="feeder" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.feeder}
        className={formik.errors.feeder && formik.touched.feeder ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.feeder && formik.touched.feeder && <span className="error-message">{formik.errors.feeder}</span>}
      <br />
      <label htmlFor="subdivision">Subdivision Name :</label><br />
      <input 
        name="subdivision" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.subdivision}
        className={formik.errors.subdivision && formik.touched.subdivision ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.subdivision && formik.touched.subdivision && <span className="error-message">{formik.errors.subdivision}</span>}
      <br />
      <label htmlFor="routecode">Route Code :</label><br />
      <input 
        name="routecode" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.routecode}
        className={formik.errors.routecode && formik.touched.routecode ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.routecode && formik.touched.routecode && <span className="error-message">{formik.errors.routecode}</span>}
      <br />
      <label htmlFor="consumerno">Consumer No :</label><br />
      <input 
        name="consumerno" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.consumerno}
        className={formik.errors.consumerno && formik.touched.consumerno ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.consumerno && formik.touched.consumerno && <span className="error-message">{formik.errors.consumerno}</span>}
      <br />
      <label htmlFor="meterno">Meter No :</label><br />
      <input 
        name="meterno" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.meterno}
        className={formik.errors.meterno && formik.touched.meterno ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.meterno && formik.touched.meterno && <span className="error-message">{formik.errors.meterno}</span>}
      <br />
    </div>

    <div className='b2-input'>

      <label htmlFor="billmonth">Bill Month :</label><br />
      <input 
        name="billmonth" 
        type="text" 
        onChange={formik.handleChange} 
        value={formik.values.billmonth} 
        placeholder='e.g: Oct , 2025'
        className={formik.errors.billmonth && formik.touched.billmonth ? 'input-error' : ''}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.billmonth && formik.touched.billmonth && <span className="error-message">{formik.errors.billmonth}</span>}
      <br />

      <label htmlFor="billdate">Bill Date :</label><br />
      <input 
        className={`init ${formik.errors.billdate && formik.touched.billdate ? 'input-error' : ''}`}
        name="billdate" 
        type="date" 
        onChange={formik.handleChange} 
        value={formik.values.billdate}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.billdate && formik.touched.billdate && <span className="error-message">{formik.errors.billdate}</span>}
      <br />

      <label htmlFor="duedate">Due Date :</label><br />
      <input 
        className={`init ${formik.errors.duedate && formik.touched.duedate ? 'input-error' : ''}`}
        name="duedate" 
        type="date" 
        onChange={formik.handleChange} 
        value={formik.values.duedate}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.duedate && formik.touched.duedate && <span className="error-message">{formik.errors.duedate}</span>}
      <br />

      <label htmlFor="fromdate">From Date :</label><br />
      <input 
        className={`init ${formik.errors.fromdate && formik.touched.fromdate ? 'input-error' : ''}`}
        name="fromdate" 
        type="date" 
        onChange={formik.handleChange} 
        value={formik.values.fromdate}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.fromdate && formik.touched.fromdate && <span className="error-message">{formik.errors.fromdate}</span>}
      <br />
      <label htmlFor="todate">To Date :</label><br />
      <input 
        className={`init ${formik.errors.todate && formik.touched.todate ? 'input-error' : ''}`}
        name="todate" 
        type="date" 
        onChange={formik.handleChange} 
        value={formik.values.todate}
        onBlur={formik.handleBlur}
      /><br />
      {formik.errors.todate && formik.touched.todate && <span className="error-message">{formik.errors.todate}</span>}
      <br />
      <label htmlFor="maxdemand">Max Demand :</label><br />
